-- Patchnote 0.8.3 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.8.3', 'patch', '2026-05-19T22:00:00.000Z',
  'Fix plugin engine compat — Discover surfaces incompatibility, prod image reports the right version',
  'Correctifs compat moteur plugins — Discover signale les incompatibilités, image prod reporte la bonne version',
  '[{"type":"fix","titleEn":"Backend reports the right Oscarr version in the prod image","titleFr":"Le backend reporte la bonne version d''Oscarr dans l''image prod","descEn":"The bundled Docker image rewrites packages/backend/package.json from a static runtime manifest (package.prod.json) at build time — that manifest still carried version 0.7.2 from three releases ago. getOscarrVersion() read from that file for plugin compat checks, so any plugin requiring Oscarr >=0.8.x (Quotas at >=0.8.2, future plugins, …) would be silently refused at install time on every Docker deployment, even though the in-app version banner correctly showed 0.8.2. Compat now reads from the root package.json (the only file shipped fresh on every release, already used by other version readers like backupService and the static APP_VERSION). The version field is dropped from package.prod.json — no more double-bump to forget.","descFr":"L''image Docker bundle réécrit packages/backend/package.json depuis un manifest runtime statique (package.prod.json) au build — ce manifest portait toujours la version 0.7.2 datant de trois releases. getOscarrVersion() lisait ce fichier pour les checks de compat plugin, donc tout plugin exigeant Oscarr >=0.8.x (Quotas en >=0.8.2, futurs plugins, …) était silencieusement refusé à l''install sur tout déploiement Docker, alors même que le bandeau de version in-app affichait correctement 0.8.2. La compat lit maintenant le package.json root (seul fichier shipped frais à chaque release, déjà utilisé par les autres lecteurs de version comme backupService et l''APP_VERSION static). Le champ version est retiré de package.prod.json — plus de double bump à oublier."},{"type":"fix","titleEn":"Discover catalog surfaces plugin engine compatibility","titleFr":"Le catalogue Discover signale la compatibilité moteur des plugins","descEn":"GET /plugins/registry now computes checkCompat per entry against the running Oscarr version and returns the result on each catalog item. The Install button on incompatible plugins is disabled and the label switches to ''Requires Oscarr <range>'' — admins see the constraint up front instead of triggering a download that the engine then refuses with a cryptic stack trace.","descFr":"GET /plugins/registry calcule désormais checkCompat par entrée contre la version Oscarr en cours et retourne le résultat sur chaque item du catalogue. Le bouton Install des plugins incompatibles est désactivé et le label devient ''Requires Oscarr <range>'' — les admins voient la contrainte directement au lieu de déclencher un download que le moteur refuse ensuite avec une stack trace cryptique."},{"type":"fix","titleEn":"Reload button now force-refreshes the Discover catalog","titleFr":"Le bouton Recharger rafraîchit aussi le catalogue Discover","descEn":"The Reload action in Admin > Plugins only bypassed the update-check cache. The Discover catalog (GET /plugins/registry) kept being served from its 30 min in-memory cache, so a newly-registered plugin or a freshly-released version of an already-listed one wouldn''t surface until the cache expired — admins had to restart Oscarr or wait. GET /plugins/registry now accepts ?force=true to bypass both the assembled catalog cache and the underlying raw-registry + per-repo release caches, and the Reload button calls it in parallel with the update check.","descFr":"L''action Recharger dans Admin > Plugins ne contournait que le cache du check d''updates. Le catalogue Discover (GET /plugins/registry) restait servi depuis son cache in-memory de 30 min, donc un plugin tout juste enregistré ou une nouvelle version d''un plugin déjà listé n''apparaissait qu''à l''expiration du cache — les admins devaient redémarrer Oscarr ou attendre. GET /plugins/registry accepte maintenant ?force=true pour contourner le cache catalogue assemblé ET les caches sous-jacents (raw registry + releases par repo), et le bouton Recharger l''appelle en parallèle du check d''updates."}]'
) ON CONFLICT ("version") DO NOTHING;
